for j = 1:6
    q_min = Robot.links(j).qlim(1);
    q_max = Robot.links(j).qlim(2);
    q_test(:, j) = q_min + (q_max - q_min) * rand(N_test, 1);
end

XSol_manual = CinematicaDirecta(q_test, Robot);

T_toolbox = Robot.fkine(q_test);
XSol_toolbox = zeros(N_test, 6);

