fprintf('Error máximo en orientación (rpy): [%g, %g, %g] rad\n', error_ori(1), error_ori(2), error_ori(3)); %[output:5d68e5c4]

if norm(error_pos) < 1e-12 && norm(error_ori) < 1e-12 %[output:group:154bda98]
    fprintf('\n[ACEPTABLE]. \n'); %[output:25631110]
else
    fprintf('\n[FAIL]: El resultado propio difiere significativamente del resultado del Toolbox.\n');
