grid on;grid minor;

err_q5(:, 1) = rad2deg((QSolution(:, 5) - q5(:, 1)));
err_q5(:, 2) = rad2deg((QSolution(:, 5) - q5(:, 2)));

figure('Name', "Error q5"); 

plot(angles, [err_q5(:, 1) err_q5(:, 2)], 'LineWidth', 1);

title('Error Absoluto q_5'); xlabel('Ángulo [rad]'); ylabel('Error Relativo [deg]');
